/* eslint-env browser */
/* eslint-disable global-require */
/* eslint no-plusplus: ["error", { "allowForLoopAfterthoughts": true }] */
/* eslint-disable import/prefer-default-export */

/**
 * Parse Json
 *
 * @param array searchData
 * @param string searchText
 *
 * @return array searchReturnData
 */
function parseJson(searchData, searchText) {
  var searchReturnData = [];

  // Check variable inputs
  if (searchData == null || searchData.length === 0 || searchText == null) {
    return false;
  }

  for (var x = 0; x < searchData.length; x++) {
    if (searchData[x].title.toLowerCase().indexOf(searchText.toLowerCase()) !== -1 || searchData[x].tags.toLowerCase().indexOf(searchText.toLowerCase()) !== -1 || searchData[x].content.toLowerCase().indexOf(searchText.toLowerCase()) !== -1) {
      searchReturnData.push([searchData[x].title, searchData[x].link, searchData[x].excerpt]);
    }
  }
  return searchReturnData;
}

/**
 * Reset Search Results
 */
function resetSearchResults() {
  var innerMenuContainer = document.getElementById('inner-menu-container');
  var searchBox = document.getElementById('search-input');
  var searchResults = document.getElementById('search-results');

  if (innerMenuContainer !== null) {
    innerMenuContainer.classList.remove('search-active');
  }

  if (searchBox !== null) {
    searchBox.value = '';
  }

  if (searchResults !== null) {
    searchResults.classList.remove('show-results');
    setTimeout(function () {
      searchResults.innerHTML = '';
    }, 200);
  }
}

/**
 * Conduct Search
 *
 * @param array searchData
 * @param string searchText
 *
 * @return searchReturn
 */
function conductSearch(searchData, searchText) {
  var searchReturn = '';

  // Check variable inputs
  if (searchData == null || searchData.length === 0 || searchText == null) {
    return false;
  }

  if (searchText !== '') {
    var searchResponse = parseJson(searchData, searchText);
    if (searchResponse.length > 0) {
      for (var x = 0; x < searchResponse.length; x++) {
        searchReturn += '<li><a href="' + searchResponse[x][1] + '">' + searchResponse[x][0] + '</a><span class="result-excerpt">' + searchResponse[x][2] + '</span></li>';
      }
    } else {
      searchReturn = '<li id="no-results">Nothing found.</li>';
    }
  } else {
    resetSearchResults();
  }
  return searchReturn;
}

/**
 * Search Init
 */
exports.searchInit = function searchInit() {
  var request = new XMLHttpRequest();
  request.responseType = 'json';

  request.onreadystatechange = function () {
    if (request.status >= 200 && request.status < 400) {
      var searching = false;
      var searchResponse = null;
      var searchReturn = null;
      var searchResults = document.getElementById('search-results');
      var innerMenuContainer = document.getElementById('inner-menu-container');
      var searchBox = document.getElementById('search-input');
      var searchContainer = document.getElementById('search-container');

      // Instant searh keybinding
      searchContainer.addEventListener('keyup', function () {
        innerMenuContainer.classList.add('search-active');
        searchBox.classList.add('loading');

        if (searching === false) {
          searching = true;
        } else {
          window.clearTimeout(searchResponse);
        }

        searchResponse = setTimeout(function () {
          searchReturn = conductSearch(request.response, searchBox.value);
          searchResults.innerHTML = '<ul>' + searchReturn + '</ul>';
          setTimeout(function () {
            searchResults.classList.add('show-results');
          }, 50);
          searching = false;
        }, 500);
      });
    }
  };

  request.open('GET', '/feed.json', true);
  request.send();
};

